module top_module(X_AEQB, AGTB, ALTB, A, B);output reg X_AEQB, AGTB, ALTB;
  input [3:0] A, B;

  always @(A,B)
  begin
    if( A === B )
      begin
        X_AEQB = 1;
        AGTB = 0;
        ALTB = 0;
      end
    else if ( A > B )
      begin
        X_AEQB = 0;
        AGTB = 1;
        ALTB = 0;
      end
    else
      begin
        X_AEQB = 0;
        AGTB = 0;
        ALTB = 1;
      end
  end
endmodule
